+  let accumulatedText = "";
+  let sawAssistantDelta = false;
+  let closed = false;
+  let unsubscribe = () => {};
+  let finalUsage: Usage | undefined;
+  let finalizeRequested: { status: ResponseResource["status"]; text: string } | null = null;
+
+  const maybeFinalize = () => {
+    if (closed) return;
+    if (!finalizeRequested) return;
+    if (!finalUsage) return;
