+
+    closed = true;
+    unsubscribe();
+
+    writeSseEvent(res, {
+      type: "response.output_text.done",
+      item_id: outputItemId,
+      output_index: 0,
+      content_index: 0,
+      text: finalizeRequested.text,
+    });
+
+    writeSseEvent(res, {
+      type: "response.content_part.done",
+      item_id: outputItemId,
+      output_index: 0,
+      content_index: 0,
+      part: { type: "output_text", text: finalizeRequested.text },
